{
    std::string name{};
    std::cin >> name;

    std::cout << "Greeting: " << PREFIX << name << '\n';
    std::cout << "Prefix length: " << PREFIX.length() << '\n';
    std::cout << "Name length: " << nameLength(name) << '\n';

    return 0;
}

